#include <vector>
#include <algorithm>

using namespace std;

class FenwickTree {
    vector<long long> tree;
    long long size;
public:
    FenwickTree(long long n) : size(n), tree(n + 1, 0) {}
    void update(long long idx, long long delta) {
        while (idx <= size) {
            tree[idx] += delta;
            idx += idx & -idx;
        }
    }
    long long query(long long idx) {
        long long res = 0;
        while (idx > 0) {
            res += tree[idx];
            idx -= idx & -idx;
        }
        return res;
    }
    long long range_query(long long l, long long r) {
        return query(r + 1) - query(l);
    }
};

long long compute_depth(long long x) {
    long long depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
        if (depth > 5) {
            return 6;
        }
    }
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    long long n = nums.size();
    vector<long long> depths(n);
    for (long long i = 0; i < n; ++i) {
        depths[i] = compute_depth(nums[i]);
    }

    vector<FenwickTree> ft(6);
    for (long long i = 0; i < 6; ++i) {
        ft[i] = FenwickTree(n);
    }

    for (long long i = 0; i < n; ++i) {
        long long d = depths[i];
        if (d >= 0 && d <= 5) {
            ft[d].update(i + 1, 1);
        }
    }

    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            long long l = q[1];
            long long r = q[2];
            long long k = q[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            answer.push_back(ft[k].range_query(l, r));
        } else {
            long long idx = q[1];
            long long val = q[2];
            long long old_val = nums[idx];
            long long old_d = depths[idx];
            if (old_d >= 0 && old_d <= 5) {
                ft[old_d].update(idx + 1, -1);
            }
            nums[idx] = val;
            long long new_d = compute_depth(val);
            if (new_d >= 0 && new_d <= 5) {
                ft[new_d].update(idx + 1, 1);
            }
            depths[idx] = new_d;
        }
    }

    return answer;
}
