#include <vector>
#include <algorithm>

using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size), tree(size + 1, 0) {}
    void update(int idx, long long delta) {
        while (idx <= size) {
            tree[idx] += delta;
            idx += idx & -idx;
        }
    }
    long long query(int idx) {
        long long res = 0;
        while (idx > 0) {
            res += tree[idx];
            idx -= idx & -idx;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

int compute_depth(long long x) {
    int depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<int> depths(n);
    for (int i = 0; i < n; ++i) {
        depths[i] = compute_depth(nums[i]);
    }

    vector<FenwickTree> ft(6);
    for (int i = 0; i < 6; ++i) {
        ft[i] = FenwickTree(n);
    }

    for (int i = 0; i < n; ++i) {
        int d = depths[i];
        if (d >= 0 && d <= 5) {
            ft[d].update(i + 1, 1);
        }
    }

    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            int l = q[1], r = q[2], k = q[3];
            if (k < 0 || k > 5) {
                answer.push_back(0);
                continue;
            }
            long long res = ft[k].range_query(l, r);
            answer.push_back(res);
        } else {
            int idx = q[1], val = q[2];
            int old_val = nums[idx];
            int old_d = depths[idx];
            if (old_d >= 0 && old_d <= 5) {
                ft[old_d].update(idx + 1, -1);
            }
            nums[idx] = val;
            int new_d = compute_depth(val);
            if (new_d >= 0 && new_d <= 5) {
                ft[new_d].update(idx + 1, 1);
            }
            depths[idx] = new_d;
        }
    }

    return answer;
}
